/// <summary>
/// Loads the initial state of the controls on the form.
/// </summary>
public void loadControlsState()
{
    next loadControlsState();

    if (personalizedControl)
    {
        TargetControlLabelId_DC.text(personalizedControl.labelId());
    }
}
